const message = $input.first().json.message || $input.first().json.callback_query?.message;
const text = message?.text || $input.first().json.callback_query?.data || '';
const chatId = message?.chat?.id || $input.first().json.callback_query?.message?.chat?.id;
const userId = message?.from?.id || $input.first().json.callback_query?.from?.id;
const firstName = message?.from?.first_name || $input.first().json.callback_query?.from?.first_name || 'paciente';

// ─── CONFIGURA POR CLIENTE ────────────────────────────────────────────────────
const CLIENTE_CONFIG = {
  id: 'fisio-garcia',
  dbId: 1,                    // ID en la tabla `clientes` de MariaDB
  nombre: 'Dr. Juan García',
  especialidad: 'Fisioterapeuta',
  horario: 'Lunes a Viernes 9:00-13:00 y 16:00-20:00',
  telefono: '+34 600 000 000',
  direccion: 'Calle Mayor 12, Valencia',
  form_url: 'https://nerv-ia.com/webhub/form.html?cliente=fisio-garcia',
  google_calendar_id: 'TU_CALENDAR_ID@group.calendar.google.com',
  servicios: [
    { nombre: 'Primera consulta', duracion: 60, precio: 50 },
    { nombre: 'Sesión de fisioterapia', duracion: 45, precio: 40 },
    { nombre: 'Rehabilitación deportiva', duracion: 60, precio: 55 }
  ]
};
// ─────────────────────────────────────────────────────────────────────────────

const esc = s => String(s || '').replace(/'/g, "''").substring(0, 1000);
const canalId = String(userId || chatId || '').replace(/[^0-9]/g, '');

return [{
  json: {
    text, chatId, userId, firstName,
    clienteConfig: CLIENTE_CONFIG,
    // Para DB
    clienteId: CLIENTE_CONFIG.dbId,
    canalId,
    textEsc: esc(text),
    nameEsc: esc(firstName)
  }
}];

